#include <stdio.h>

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        int grid[205][205];
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                scanf("%d", &grid[i][j]);
            }
        }
        int dp[205][205];
        dp[0][0] = grid[0][0];
        for (int j = 1; j < N; ++j) dp[0][j] = dp[0][j-1] + grid[0][j];
        for (int i = 1; i < N; ++i) {
            dp[i][0] = dp[i-1][0] + grid[i][0];
            for (int j = 1; j < N; ++j) {
                dp[i][j] = (dp[i-1][j] < dp[i][j-1] ? dp[i-1][j] : dp[i][j-1]) + grid[i][j];
            }
        }
        printf("%d\n", dp[N-1][N-1]);
    }
    return 0;
}

